const catalog = [
  { supplier: 'Getaz Miauton (synthetic)', sku: 'GETAZ-SYN-001', description: 'Flexible alimentation DN15', aliases: ['flexible alimentation dn15', 'flexible dn15'], unitPriceChf: 42.5 },
  { supplier: 'Sanitas Troesch (synthetic)', sku: 'SANITAS-SYN-101', description: 'Mitigeur lavabo chrome', aliases: ['mitigeur lavabo chrome'], unitPriceChf: 175 },
  { supplier: 'Nussbaum (synthetic)', sku: 'NUSSBAUM-SYN-201', description: 'Vanne a bille 1/2', aliases: ['vanne a bille 1/2', 'vanne bille 1/2'], unitPriceChf: 65 },
];
const normalize = value => String(value ?? '').normalize('NFKD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/[^a-z0-9\/.-]+/g, ' ').trim().replace(/\s+/g, ' ');
const money = value => Math.round((Number(value) + Number.EPSILON) * 100) / 100;
const index = new Map();
for (const item of catalog) for (const key of [item.sku, item.description, ...item.aliases]) index.set(normalize(key), item);
const request = String($json.request ?? '2 x flexible DN15; mitigeur lavabo chrome; raccord inconnu');
const lines = request.split(/[;\n]+/).map(value => value.trim()).filter(Boolean).map(original => { const match = original.match(/^\s*(?:(\d+(?:[.,]\d+)?)\s*(?:x|×)\s*)?(.+?)\s*$/i); const quantity = Number(String(match?.[1] ?? '1').replace(',', '.')); if (!Number.isFinite(quantity) || quantity <= 0 || quantity > 1000) throw new Error('Invalid quantity'); return { original, quantity, description: match[2] }; });
const matched = []; const exceptions = [];
for (const line of lines) { const item = index.get(normalize(line.description)); if (!item) { exceptions.push({ requested: line.original, quantity: line.quantity, reason: 'NO_EXACT_CATALOG_MATCH', priced: false }); continue; } matched.push({ requested: line.original, supplier: item.supplier, sku: item.sku, catalogDescription: item.description, quantity: line.quantity, unitPriceChf: item.unitPriceChf, materialBaseChf: money(line.quantity * item.unitPriceChf), exactMatch: true }); }
const laborHours = Number($json.laborHours ?? 0); if (!Number.isFinite(laborHours) || laborHours < 0) throw new Error('Invalid labor hours');
const materialBaseChf = money(matched.reduce((sum, row) => sum + row.materialBaseChf, 0));
const materialMarginChf = money(materialBaseChf * 0.15); const materialsWithMarginChf = money(materialBaseChf + materialMarginChf); const laborChf = money(laborHours * 95); const travelChf = $json.includeTravel === false ? 0 : 45; const subtotalChf = money(materialsWithMarginChf + laborChf + travelChf); const vatChf = money(subtotalChf * 0.081);
return [{ json: { status: exceptions.length ? 'REVIEW_REQUIRED' : 'READY', reviewRequired: exceptions.length > 0, currency: 'CHF', catalogMode: 'SYNTHETIC_EXACT_MATCH_ONLY', matched, exceptions, pricing: { materialBaseChf, materialMarginRate: 0.15, materialMarginChf, materialsWithMarginChf, laborHours, laborRateChf: 95, laborChf, travelChf, subtotalChf, vatRate: 0.081, vatChf, totalChf: money(subtotalChf + vatChf) } } }];
